function formatDateTime(iso){try{return new Intl.DateTimeFormat(state.lang==='gl'?'gl-ES':state.lang,{dateStyle:'short',timeStyle:'short'}).format(new Date(iso))}catch(e){return iso}}function updateBadge(iso){state.data.last_updated_at=iso;const el=document.getElementById('updateBadge');if(el)el.textContent=`${T('update')}: ${formatDateTime(iso)}`}
function smallCardHTML(route,title,text){return `<a href="#${route}" data-route="${route}" class="mini-card"><span class="card-arrow">↗</span><h3>${escapeHTML(title)}</h3><p>${escapeHTML(text)}</p></a>`}
function renderHomeCards(){document.getElementById('homeQuestions').innerHTML=[smallCardHTML('aventura',T('sim'),'Constrúe unha ruta visual con bifurcacións.'),smallCardHTML('inicio',T('finderTitle'),'Busca por nome, familia ou tipo.'),smallCardHTML('becas',T('becasTitle'),'Beca xeral, NEAE e convocatorias.'),smallCardHTML('cupos',T('cuposTitle'),'Discapacidade, deportistas e outras vías.'),smallCardHTML('faq',T('faqTitle'),'Preguntas frecuentes con fontes.'),smallCardHTML('asistente',T('bot'),'Asistencia personalizada e prudente.')].join('')}
function contentCards(items){return items.map(x=>`<article class="content-card"><h2>${escapeHTML(x.title)}</h2><p>${escapeHTML(x.body)}</p>${sourceLinks(x.sources)}</article>`).join('')}
const ROUTES=[{title:'ESO con título',body:'Bachillerato, FP de grado medio, enseñanzas artísticas y deportivas, según requisitos.',sources:['educagob-eso','todofp']},{title:'ESO sin título',body:'FP básica, educación de adultos, pruebas de acceso u otras vías según edad y convocatoria.',sources:['educagob-eso','xunta-fp-oferta']},{title:'Bachillerato',body:'Puerta a universidad, FP superior, enseñanzas artísticas superiores y otras vías.',sources:['educagob-bach-organizacion','ciug-admision']},{title:'FP',body:'Permite empleo, continuidad a grado superior y acceso universitario desde FP superior.',sources:['todofp','xunta-fp-oferta']}];
const BACH=[{title:'Ciencias y Tecnología',body:'Vía habitual para salud, ciencias, informática, arquitectura e ingenierías. Revisar Matemáticas II, Física, Química, Biología y Dibujo Técnico II.',sources:['educagob-bach-organizacion','ciug-ponderaciones-2026']},{title:'Humanidades y Ciencias Sociales',body:'Vía habitual para Derecho, empresa, educación, historia, filologías y ciencias sociales. Revisar MACS II, Latín II, Geografía, Empresa e Historia del Arte.',sources:['educagob-bach-organizacion','ciug-ponderaciones-2026']},{title:'Artes',body:'Vía para artes, diseño, música, danza o arte dramático, con posibles pruebas específicas.',sources:['educagob-bach-organizacion','infoartisticas-ensenanzas']},{title:'Bachillerato General',body:'Opción para perfiles abiertos; no debe elegirse por descarte si el objetivo exige materias muy concretas.',sources:['educagob-bach-organizacion','ciug-ponderaciones-2026']}];
const FP=[{title:'Oferta real por centros',body:'La oferta de FP debe comprobarse por curso, régimen, centro, localidad y plazas en la Xunta.',sources:['xunta-fp-oferta','xunta-fp-centros']},{title:'Familias profesionales',body:'TodoFP permite explorar familias, niveles, ciclos y perfiles profesionales.',sources:['todofp','todofp-familias']},{title:'Ciclos de grado medio',body:'Normalmente desde ESO, con otras vías posibles por prueba o requisitos específicos.',sources:['educagob-eso','todofp']},{title:'Ciclos de grado superior',body:'Pueden abrir empleo cualificado y acceso universitario.',sources:['todofp','ciug-admision']}];
