function renderStaticSections(){document.getElementById('routeCards').innerHTML=contentCards(ROUTES);document.getElementById('bachCards').innerHTML=contentCards(BACH);document.getElementById('bachWarning').innerHTML='<strong>'+T('important')+':</strong> '+T('officialNote');document.getElementById('fpCards').innerHTML=contentCards(FP);document.getElementById('universityCards').innerHTML=contentCards(UNI);document.getElementById('masterCards').innerHTML=state.data.studies.filter(p=>p.regulated?.toLowerCase().includes('máster')||p.level?.toLowerCase().includes('máster')).slice(0,4).map(p=>programCard(p)).join('');document.getElementById('ponderationLinks').innerHTML=sourceLinks(['ciug-admision','ciug-ponderaciones-2026']);document.getElementById('areaButtons').innerHTML=[...new Set(state.data.studies.map(p=>p.family))].map(f=>`<button type="button" data-family="${escapeHTML(f)}">${escapeHTML(f)}</button>`).join('');document.querySelectorAll('#areaButtons button').forEach(b=>b.onclick=()=>document.getElementById('areaOutput').innerHTML=programs('', 'all', b.dataset.family).map(p=>programCard(p)).join(''));document.getElementById('scholarshipCards').innerHTML=state.data.scholarships.map(s=>`<article class="scholarship-card"><h2>${escapeHTML(s.title)}</h2><p>${escapeHTML(s.summary)}</p><p><strong>Prazo/estado:</strong> ${escapeHTML(s.period)}</p>${sourceLinks(s.sources)}</article>`).join('');document.getElementById('reservedCards').innerHTML=state.data.reservations.map(s=>`<article class="scholarship-card"><h2>${escapeHTML(s.title)}</h2><p>${escapeHTML(s.summary)}</p>${sourceLinks(s.sources)}</article>`).join('');renderSources();renderFAQ();}
function renderSources(){const cats=['all','itinerarios','fp','universidad','becas','empleo','normativa'];document.getElementById('sourceFilters').innerHTML=cats.map(c=>`<button class="chip ${state.sourceFilter===c?'active':''}" data-cat="${c}">${escapeHTML(c==='all'?T('all'):c)}</button>`).join('');document.querySelectorAll('#sourceFilters button').forEach(b=>b.onclick=()=>{state.sourceFilter=b.dataset.cat;renderSources()});const list=state.data.official_sources.filter(s=>state.sourceFilter==='all'||s.category===state.sourceFilter);document.getElementById('sourceCards').innerHTML=list.map(s=>`<article class="content-card"><h2>${escapeHTML(s.title)}</h2><p>${escapeHTML(s.use)}</p><a class="button primary" target="_blank" rel="noopener noreferrer" href="${s.url}">${T('sources')}</a></article>`).join('')}
function renderFAQ(){const q=normalise(document.getElementById('faqSearch')?.value||'');const list=state.data.faq.filter(x=>!q||normalise(x.q+' '+x.a).includes(q));document.getElementById('faqList').innerHTML=list.map(x=>`<details class="faq-item"><summary>${escapeHTML(x.q)}</summary><p>${escapeHTML(x.a)}</p>${sourceLinks(x.sources)}</details>`).join('')}
function renderTags(){document.getElementById('quickTags').innerHTML=['electricidad','soldadura','arquitectura','psicología','derecho','beca NEAE','discapacidad','deportista alto nivel'].map(t=>`<button type="button" data-tag="${escapeHTML(t)}">${escapeHTML(t)}</button>`).join('');document.querySelectorAll('#quickTags button').forEach(b=>b.onclick=()=>{document.getElementById('studySearch').value=b.dataset.tag;runSearch()})}
function renderAdventure(){document.getElementById('adventureStartOptions').innerHTML=[['eso_cursando','Estoy cursando ESO'],['eso_titulo','Tengo título de ESO'],['eso_sin','No tengo título de ESO'],['bach','Estoy en Bachillerato'],['fpgm','Estoy en Grado Medio'],['fpgs','Estoy en Grado Superior'],['grado','Ya tengo un grado']].map(([id,l])=>`<button class="${state.adventure.start===id?'active':''}" data-start="${id}">${escapeHTML(l)}</button>`).join('');document.querySelectorAll('[data-start]').forEach(b=>b.onclick=()=>{state.adventure.start=b.dataset.start;state.adventure.step=2;renderAdventure();scrollWizard(2)});document.getElementById('adventureGoalOptions').innerHTML=['arquitectura','psicología','electricidad','soldadura','medicina','derecho','informática','enfermería'].map(g=>`<button data-goal="${escapeHTML(g)}">${escapeHTML(g)}</button>`).join('');document.querySelectorAll('[data-goal]').forEach(b=>b.onclick=()=>{document.getElementById('adventureGoalSearch').value=b.dataset.goal;state.adventure.goalText=b.dataset.goal;state.adventure.selectedProgramId=null;state.adventure.step=3;renderAdventure();scrollWizard(3)});document.getElementById('adventureGoalSearch').oninput=e=>{state.adventure.goalText=e.target.value;state.adventure.selectedProgramId=null;renderAdventure()};const matches=programs(state.adventure.goalText);const dis=document.getElementById('adventureDisambiguation');if(state.adventure.goalText&&isAmbiguous(matches)){dis.innerHTML=`<p class="warning-box small">${T('ambiguity')}</p>`+matches.slice(0,5).map(p=>`<button class="choice-card" data-pid="${p.id}">${escapeHTML(p.name)}<br><small>${escapeHTML(p.family)} · ${escapeHTML(p.level)}</small></button>`).join('');dis.querySelectorAll('[data-pid]').forEach(b=>b.onclick=()=>{state.adventure.selectedProgramId=b.dataset.pid;state.adventure.step=3;renderAdventure();scrollWizard(3)})}else dis.innerHTML='';document.getElementById('adventureQuestions').innerHTML=[['balanced','Ruta equilibrada'],['direct','Ruta más directa'],['open','Mantener alternativas'],['support','Necesito apoyo con materias difíciles']].map(([id,l])=>`<button class="${state.adventure.adjustment===id?'active':''}" data-adjust="${id}">${escapeHTML(l)}</button>`).join('');document.querySelectorAll('[data-adjust]').forEach(b=>b.onclick=()=>{state.adventure.adjustment=b.dataset.adjust;renderAdventureResult()});document.querySelectorAll('.wizard-step').forEach((el,i)=>el.classList.toggle('active',i+1===state.adventure.step));document.querySelectorAll('.wizard-progress span').forEach((el,i)=>el.classList.toggle('active',i+1<=state.adventure.step));renderAdventureResult()}
function selectedProgram(){return state.data.studies.find(p=>p.id===state.adventure.selectedProgramId)||programs(state.adventure.goalText)[0]}
function renderAdventureResult(){const stage=document.getElementById('adventureResult');if(!state.adventure.start||!state.adventure.goalText){stage.innerHTML=`<div class="route-board"><div class="route-intro"><h2>${T('sim')}</h2><p>${T('chooseStart')} ${T('chooseGoal')}</p></div></div>`;return}const p=selectedProgram();if(!p){stage.innerHTML=`<div class="route-board"><div class="route-intro"><h2>${T('sim')}</h2><p>${T('officialNote')}</p>${sourceLinks(['todofp-familias','xunta-fp-oferta','qedu','ruct'])}</div></div>`;return}let options=p.route_options?.length?p.route_options:[{title:'Ruta principal',steps:p.route.split('→').map(s=>s.trim())}];if(state.adventure.start==='eso_sin')options=[{title:'Regularizar acceso',steps:['ESO sin título','FP básica / adultos / prueba','Siguiente etapa compatible',p.name]}].concat(options);if(state.adventure.start==='fpgs'&&p.type==='grado')options=[{title:'Desde FP superior a universidad',steps:['FP grado superior','Admisión universitaria','Revisar nota y ponderaciones','Grado objetivo']}].concat(options);stage.innerHTML=`<div class="route-board" id="journeyPrintable"><div class="route-intro"><p class="eyebrow">${T('sim')}</p><h2>${escapeHTML(p.name)}</h2><p>${escapeHTML(p.regulated)}</p></div><div class="branch-grid">${options.map((opt,bi)=>`<div class="branch"><div class="branch-title">${escapeHTML(opt.title)}</div><div class="route-steps">${opt.steps.map((s,i)=>`<div class="route-node"><button type="button" data-node="${bi}-${i}"><strong>${i+1}. ${escapeHTML(s)}</strong><small>Clic para ampliar</small></button></div>`).join('')}</div></div>`).join('')}</div><div class="route-info-panel" id="routeInfo"><h3>${T('important')}</h3><p>${escapeHTML(p.demand)}</p><p><strong>${T('subjects')}:</strong> ${p.subjects.map(escapeHTML).join(', ')}</p>${ponderationHTML(p)}${availabilityHTML(p)}<p class="warning-box small">${T('officialNote')}</p><div class="result-actions"><button type="button" class="button pdf-button" onclick="exportPDF('journeyPrintable','ITINERA · ${escapeHTML(p.name)}')">${T('pdf')}</button></div>${sourceLinks(p.sources)}</div></div>`;document.querySelectorAll('[data-node]').forEach(btn=>btn.onclick=()=>{const info=document.getElementById('routeInfo');info.scrollIntoView({behavior:'smooth',block:'nearest'});info.classList.add('flash');setTimeout(()=>info.classList.remove('flash'),600)})}
function scrollWizard(n){setTimeout(()=>document.getElementById('wizardStep'+n)?.scrollIntoView({behavior:'smooth',block:'nearest'}),80)}
function simulateProgram(id){state.adventure.selectedProgramId=id;state.adventure.goalText=state.data.studies.find(p=>p.id===id)?.name||'';state.adventure.step=3;routeTo('aventura');renderAdventure()}
function botAnswer(text){const q=normalise(text);const p=programs(text)[0];if(q.includes('matematic')&&q.includes('psicolog'))return `<p>Se quieres Psicología pero las matemáticas no se te dan bien, no elijas solo por ponderación. Compara tres cosas: cuánto pondera cada materia en CIUG, qué nota realista puedes sacar y qué base te aporta. A veces una materia que pondera menos pero dominas mejor puede ser más rentable que una materia difícil. Revisa Biología, MACS II u otras materias según la tabla vigente.</p>${sourceLinks(['ciug-ponderaciones-2026','ciug-admision'])}`;if(q.includes('nota')||q.includes('corte'))return `<p>Las notas de corte cambian cada curso y no deben memorizarse como garantía. Para Galicia, consulta CIUG y filtra por grado, universidad y convocatoria.</p>${sourceLinks(['ciug-admision'])}`;if(q.includes('beca')||q.includes('neae'))return document.getElementById('scholarshipCards').innerHTML || `<p>Consulta el portal oficial de Becas Educación.</p>${sourceLinks(['becas-portada','beca-general','beca-neae'])}`;if(q.includes('discapacidad')||q.includes('deportista')||q.includes('cupo'))return document.getElementById('reservedCards').innerHTML;if(p&&p.score>.45)return programCard(p,p.score<1.1);return `<p>${T('officialNote')}</p>${sourceLinks(['todofp-familias','xunta-fp-oferta','qedu','ruct','ciug-admision'])}`}
function addMsg(kind,html){const log=document.getElementById('chatLog');const div=document.createElement('div');div.className='msg '+kind;div.innerHTML=html;log.appendChild(div);log.scrollTop=log.scrollHeight}function resetChat(){const log=document.getElementById('chatLog');log.innerHTML='';addMsg('bot',`<p>${T('greeting')}</p>`)}function renderQuestionChips(){document.getElementById('questionChips').innerHTML=['Quiero psicología pero no se me dan bien las matemáticas','¿Dónde veo notas de corte?','¿Qué becas oficiales hay?','¿Hay plazas por discapacidad?','Electricidad: ¿qué opciones hay?'].map(q=>`<button class="question-chip" type="button">${escapeHTML(q)}</button>`).join('');document.querySelectorAll('.question-chip').forEach(b=>b.onclick=()=>{document.getElementById('chatInput').value=b.textContent;document.getElementById('chatForm').dispatchEvent(new Event('submit'))})}
function exportPDF(elementId,title){const el=document.getElementById(elementId);if(!el)return window.print();const report=document.createElement('section');report.className='print-report';report.innerHTML=`<div class="pdf-header"><img class="pdf-logo" src="assets/itinera-symbol.png"><div><h1>${escapeHTML(title||'ITINERA')}</h1><p>${formatDateTime(state.data.last_updated_at||LAST_UPDATED_AT)}</p></div></div><main>${el.innerHTML}</main><div class="pdf-footer"><img class="pdf-shield" src="assets/tribeca-shield.png"><div><strong>Tribeca Academia</strong><br>Calle Rafael Juan, 33, 15130, Corcubión, A Coruña<br>CC BY-NC-SA 4.0</div></div>`;document.body.appendChild(report);document.body.classList.add('printing-report');setTimeout(()=>{window.print();document.body.classList.remove('printing-report');report.remove()},100)}
function routeTo(id){const target=id||'inicio';document.querySelectorAll('.view').forEach(v=>v.classList.remove('active-view'));(document.getElementById(target)||document.getElementById('inicio')).classList.add('active-view');document.querySelectorAll('[data-route]').forEach(a=>a.classList.toggle('active',a.dataset.route===target));location.hash=target;document.getElementById('mainNav').classList.remove('open')}
function bindRoutes(){document.querySelectorAll('[data-route]').forEach(a=>{if(a.dataset.bound)return;a.dataset.bound=1;a.onclick=e=>{e.preventDefault();routeTo(a.dataset.route)}})}
function init(){renderBasics();renderHeadings();renderSelects();renderHomeCards();renderStaticSections();renderTags();renderAdventure();renderQuestionChips();bindRoutes();resetChat();document.getElementById('studySearchBtn').onclick=runSearch;document.getElementById('studySearch').onkeydown=e=>{if(e.key==='Enter')runSearch()};document.getElementById('studyTypeFilter').onchange=runSearch;document.getElementById('familyFilter').onchange=runSearch;document.getElementById('faqSearch').oninput=renderFAQ;document.getElementById('languageSelect').onchange=e=>{state.lang=e.target.value;localStorage.setItem('itineraLang',state.lang);init()};document.getElementById('fontSelect').onchange=e=>{state.font=e.target.value;localStorage.setItem('itineraFont',state.font);renderBasics()};document.getElementById('chatForm').onsubmit=e=>{e.preventDefault();const input=document.getElementById('chatInput');const txt=input.value.trim();if(!txt)return;addMsg('user',`<p>${escapeHTML(txt)}</p>`);addMsg('bot',botAnswer(txt));input.value=''};document.getElementById('navToggle').onclick=()=>document.getElementById('mainNav').classList.toggle('open');document.getElementById('adventurePdfBtn').onclick=()=>exportPDF('adventureResult','ITINERA · Simula tu itinerario');document.querySelectorAll('[data-modal-open]').forEach(b=>b.onclick=()=>openModal(b.dataset.modalOpen));document.querySelectorAll('[data-modal-close]').forEach(b=>b.onclick=closeModal);document.getElementById('modalBackdrop').onclick=closeModal;routeTo(location.hash.replace('#','')||'inicio')}
function openModal(id){document.getElementById('modalBackdrop').hidden=false;document.getElementById(id).hidden=false}function closeModal(){document.getElementById('modalBackdrop').hidden=true;document.querySelectorAll('.modal').forEach(m=>m.hidden=true)}/* ITINERA v0.9 overrides: navegación, simulador, FAQ, universidad e ItineraBot */
