function showStudySheet(id){
  const p=state.data.studies.find(x=>x.id===id);
  if(!p) return;
  openDetailModal(T('studySheet'), studySheetHTML(p));
}
function studySheetHTML(p){
  return `<article class="study-sheet">
    <header class="sheet-head"><h2>${escapeHTML(p.name)}</h2><div class="badges"><span class="badge">${escapeHTML(p.level)}</span><span class="badge">${escapeHTML(p.family)}</span></div></header>
    <section><h3>Ruta</h3><p>${escapeHTML(p.route)}</p></section>
    <section><h3>${T('subjects')}</h3><p>${(p.subjects||[]).map(escapeHTML).join(', ') || 'Comprobar plan oficial.'}</p></section>
    ${ponderationHTML(p)}
    <section><h3>${T('important')}</h3><p>${escapeHTML(p.regulated||'Comprobar requisitos oficiais.')}</p></section>
    <section><h3>Demanda / empleo</h3><p>${escapeHTML(p.demand||'Consultar fuentes oficiales de empleo y oferta territorial.')}</p></section>
    ${availabilityHTML(p)}
    <p class="warning-box small">${T('officialNote')}</p>
    <div class="result-actions sheet-actions">
      <button type="button" class="button pdf-button" onclick="exportPDFPremiumFromHTML('ITINERA · ${escapeHTML(p.name)}', document.getElementById('studyDetailBody').innerHTML)">${T('pdf')}</button>
      <button type="button" class="button action-sim" onclick="closeModal();simulateProgram('${p.id}')">${T('designRoute')}</button>
    </div>
    ${sourceLinks(p.sources)}
  </article>`;
}
programCard = function(p,approx=false){
  return `<article class="result-card study-mini-card">${approx?`<p class="eyebrow">${T('maybe')}: ${escapeHTML(p.name)}</p>`:''}<h3>${escapeHTML(p.name)}</h3><div class="badges"><span class="badge">${escapeHTML(p.level)}</span><span class="badge">${escapeHTML(p.family)}</span></div><p><strong>${T('route')}:</strong> ${escapeHTML(p.route)}</p><p><strong>${T('subjects')}:</strong> ${(p.subjects||[]).map(escapeHTML).join(', ')}</p><p><strong>${T('important')}:</strong> ${escapeHTML(p.regulated)}</p>${availabilityHTML(p)}<div class="result-actions"><button type="button" class="button primary" onclick="showStudySheet('${p.id}')">${T('seeSheet')}</button><button type="button" class="button action-sim" onclick="simulateProgram('${p.id}')">${T('designRoute')}</button></div>${sourceLinks(p.sources)}</article>`;
};

function renderStudiesBrowser(){
  const search=document.getElementById('allStudiesSearch');
  const type=document.getElementById('allStudiesType');
  const family=document.getElementById('allStudiesFamily');
  if(!search||!type||!family) return;
  const types=[['all',T('allTypes')],['fpgm','FP grado medio'],['fpgs','FP grado superior'],['grado','Grado universitario'],['master','Máster']];
  type.innerHTML=types.map(([v,l])=>`<option value="${v}">${escapeHTML(l)}</option>`).join('');
  const families=[...new Set(state.data.studies.map(p=>p.family))].sort();
  family.innerHTML=`<option value="all">${T('allFamilies')}</option>`+families.map(f=>`<option value="${escapeHTML(f)}">${escapeHTML(f)}</option>`).join('');
  const draw=()=>{
    const list=programs(search.value,type.value,family.value).slice(0,80);
    document.getElementById('allStudiesList').innerHTML=list.map(p=>`<button class="study-list-item" type="button" onclick="showStudySheet('${p.id}')"><strong>${escapeHTML(p.name)}</strong><span>${escapeHTML(p.level)} · ${escapeHTML(p.family)}</span></button>`).join('') || `<div class="warning-box">${T('officialNote')}${sourceLinks(['todofp-familias','xunta-fp-oferta','qedu','ruct'])}</div>`;
  };
  search.oninput=draw; type.onchange=draw; family.onchange=draw; draw();
}

function connectionInfoHTML(conn,nextLabel){
  let sources=['todofp'];
  if(conn.type==='access') sources=['xunta-proba-gm-info-2026','xunta-proba-gs-info-2026','xunta-proba-gs-xeral','xunta-exames-probas'];
  if(conn.type==='critical') sources=['ciug-admision','ciug-ponderaciones-2026','ciug-notas-corte'];
  return `<div class="connector-detail"><p>${escapeHTML(conn.info||'Comprobar requisito oficial antes de avanzar.')}</p><p><strong>Siguiente paso:</strong> ${escapeHTML(nextLabel||'')}</p>${sourceLinks(sources)}</div>`;
}
function routeStep(label, kind='stage', info=''){
  return {label,kind,info};
}
function connector(kind='direct', label='Acceso directo', info=''){
  return {kind:'connector',type:kind,label,info};
}
function buildVisualRoute(program){
  const s=state.adventure.start;
  const p=program;
  const routes=[];
  const add=(title,items)=>routes.push({title,items});
  if((s==='eso_cursando'||s==='eso_titulo')&&p.type==='fpgs'){
    add('Vía por Bachillerato',[
      routeStep('ESO','start','Punto de partida.'),
      connector('direct','Flecha directa','Con título de ESO se puede continuar a Bachillerato.'),
      routeStep('Bachillerato','stage','Vía ordinaria para acceder a ciclos superiores.'),
      connector('direct','Flecha directa','Con Bachillerato se puede solicitar admisión a FP superior, sujeta a plazas y criterios.'),
      routeStep(p.name,'goal','Ciclo formativo de grado superior.')
    ]);
    add('Vía por FP de grado medio',[
      routeStep('ESO','start','Punto de partida.'),
      connector('direct','Flecha directa','Con ESO se puede solicitar un ciclo de grado medio.'),
      routeStep('FP grado medio','stage','Preferentemente de familia afín si se desea continuidad técnica.'),
      connector('direct','Flecha directa','Desde un ciclo medio puede solicitarse admisión a grado superior, según normativa y plazas.'),
      routeStep(p.name,'goal','Ciclo formativo de grado superior.')
    ]);
    add('Vía con prueba de acceso',[
      routeStep('ESO','start','No hay acceso directo ordinario desde ESO a grado superior.'),
      connector('access','Prueba de acceso GS','Requiere cumplir requisito de edad y superar la prueba de acceso a grado superior. Parte común y parte específica.'),
      routeStep(p.name,'goal','Acceso condicionado a superación de prueba, admisión y plazas.')
    ]);
  } else if((s==='eso_cursando'||s==='eso_titulo')&&p.type==='fpgm'){
    add('Ruta directa a grado medio',[
      routeStep('ESO','start','Con título de ESO o requisito equivalente.'),
      connector('direct','Flecha directa','Puede solicitarse admisión a ciclo de grado medio.'),
      routeStep(p.name,'goal','Ciclo formativo de grado medio.')
    ]);
  } else if((s==='eso_cursando'||s==='eso_titulo')&&p.type==='grado'){
    add('Ruta universitaria ordinaria',[
      routeStep('ESO','start','Punto de partida.'),
      connector('direct','Flecha directa','Continuidad académica hacia Bachillerato.'),
      routeStep('Bachillerato adecuado','stage','Escoger modalidad y materias coherentes.'),
      connector('critical','PAU/ABAU y ponderaciones','Punto crítico: materias ponderables, nota de admisión y consulta CIUG.'),
      routeStep(p.name,'goal','Grado universitario.')
    ]);
    add('Ruta alternativa por FP superior',[
      routeStep('ESO','start','Punto de partida.'),
      connector('direct','Flecha directa','Acceso a FP de grado medio con requisito ordinario.'),
      routeStep('FP grado medio','stage','Primer ciclo profesional.'),
      connector('direct','Flecha directa','Continuidad a FP superior, según admisión.'),
      routeStep('FP grado superior','stage','Vía de acceso a universidad.'),
      connector('critical','Admisión universitaria','Puede requerir mejorar nota con materias de admisión.'),
      routeStep(p.name,'goal','Grado universitario.')
    ]);
  } else if(s==='eso_sin'){
    if(p.type==='fpgm'){
      add('Vía con prueba a grado medio',[
        routeStep('ESO sin título','start','Punto de partida.'),
        connector('access','Prueba de acceso GM','Parte sociolingüística, matemática y científico-técnica.'),
        routeStep(p.name,'goal','Ciclo de grado medio.')
      ]);
    } else {
      add('Primero regularizar acceso',[
        routeStep('ESO sin título','start','Punto de partida.'),
        connector('access','Regularización / prueba','Antes de llegar a esta meta hay que cumplir requisitos intermedios.'),
        routeStep('ESO adultos, FP básica o GM','stage','Vía previa según edad y convocatoria.'),
        connector('direct','Continuidad','Después se elige la vía compatible.'),
        routeStep(p.name,'goal','Meta.')
      ]);
    }
  } else if(s==='bach'){
    if(p.type==='grado'){
      add('Desde Bachillerato a universidad',[
        routeStep('Bachillerato','start','Punto de partida.'),
        connector('critical','PAU/ABAU','Revisar fase general, materias ponderables, notas de corte y CIUG.'),
        routeStep(p.name,'goal','Grado universitario.')
      ]);
    } else if(p.type==='fpgs'){
      add('Desde Bachillerato a FP superior',[
        routeStep('Bachillerato','start','Requisito ordinario.'),
        connector('direct','Flecha directa','Solicitud de admisión a FP superior, sujeta a plazas.'),
        routeStep(p.name,'goal','Ciclo superior.')
      ]);
    } else {
      add('Ruta compatible desde Bachillerato',[routeStep('Bachillerato','start','Punto de partida.'),connector('direct','Flecha directa','Solicitud según admisión.'),routeStep(p.name,'goal','Meta.')]);
    }
  } else if(s==='fpgm'){
    if(p.type==='fpgs'){
      add('Continuidad hacia grado superior',[routeStep('FP grado medio','start','Punto de partida.'),connector('direct','Flecha directa','Acceso a grado superior, sujeto a admisión y plazas.'),routeStep(p.name,'goal','Ciclo superior.')]);
    } else if(p.type==='grado'){
      add('FP media → FP superior → universidad',[routeStep('FP grado medio','start','Punto de partida.'),connector('direct','Flecha directa','Continuidad hacia FP superior.'),routeStep('FP grado superior','stage','Vía de acceso a universidad.'),connector('critical','Admisión universitaria','Puede requerir nota de admisión y materias específicas.'),routeStep(p.name,'goal','Grado universitario.')]);
    } else add('Ruta orientativa',[routeStep('FP grado medio','start','Punto de partida.'),connector('direct','Flecha directa','Comprobar requisito.'),routeStep(p.name,'goal','Meta.')]);
  } else if(s==='fpgs'){
    if(p.type==='grado'){
      add('Desde FP superior a universidad',[routeStep('FP grado superior','start','Vía de acceso.'),connector('critical','Admisión universitaria','Revisar nota, plazas y posible mejora con materias.'),routeStep(p.name,'goal','Grado universitario.')]);
    } else add('Continuidad desde FP superior',[routeStep('FP grado superior','start','Punto de partida.'),connector('direct','Flecha directa','Comprobar requisitos.'),routeStep(p.name,'goal','Meta.')]);
  } else if(s==='grado'){
    add('Después de un grado',[routeStep('Grado universitario','start','Punto de partida.'),connector('critical','Comprobar profesión regulada','Revisar si exige máster habilitante o formación específica.'),routeStep(p.level?.toLowerCase().includes('máster')?p.name:'Máster o especialización','stage','Si procede.'),connector('direct','Flecha directa','Ejercicio o continuidad según normativa.'),routeStep('Meta profesional','goal','Salida final.')]);
  } else {
    add('Ruta orientativa',[routeStep('Punto de partida','start','Selecciona etapa.'),connector('direct','Flecha directa','Comprobar requisito.'),routeStep(p.name,'goal','Meta.')]);
  }
  return routes;
}
function connectorButtonHTML(conn,nextLabel,idx){
  const cls=conn.type==='direct'?'direct-link':conn.type==='access'?'access-link':'critical-link';
  const label=conn.type==='direct'?'→':conn.type==='access'?'requisito':'clave';
  return `<button type="button" class="route-connector ${cls}" data-cinfo="${escapeHTML(conn.info)}" data-ctitle="${escapeHTML(conn.label)}" data-next="${escapeHTML(nextLabel)}"><span>${escapeHTML(label)}</span></button>`;
}
renderAdventureResult = function(){
  const stage=document.getElementById('adventureResult');
  if(!state.adventure.start||!state.adventure.goalText){
    stage.innerHTML=`<div class="route-board route-board-soft"><div class="route-intro"><h2>${T('sim')}</h2><p>${T('chooseStart')} ${T('chooseGoal')}</p></div></div>`;return;
  }
  const p=selectedProgram();
  if(!p){stage.innerHTML=`<div class="route-board route-board-soft"><div class="route-intro"><h2>${T('sim')}</h2><p>${T('officialNote')}</p>${sourceLinks(['todofp-familias','xunta-fp-oferta','qedu','ruct'])}</div></div>`;return;}
  const routes=buildVisualRoute(p);
  stage.innerHTML=`<div class="route-board route-board-soft" id="journeyPrintable">
    <div class="route-intro route-intro-soft"><p class="eyebrow">${T('sim')}</p><h2>${escapeHTML(p.name)}</h2><p>${escapeHTML(p.route)}</p><div class="result-actions"><button type="button" class="button primary" onclick="showStudySheet('${p.id}')">${T('seeSheet')}</button><button type="button" class="button pdf-button" onclick="exportPDF('journeyPrintable','ITINERA · ${escapeHTML(p.name)}')">${T('pdf')}</button></div></div>
    <div class="route-legend"><span><i class="legend-arrow"></i> ${T('connectorDirect')}</span><span><i class="legend-access"></i> ${T('connectorAccess')}</span><span><i class="legend-critical"></i> ${T('connectorCritical')}</span></div>
    <div class="branch-grid branch-grid-soft">${routes.map((route,ri)=>`<div class="branch branch-soft"><div class="branch-title">${escapeHTML(route.title)}</div><div class="route-flow">${route.items.map((it,i)=>{
      if(it.kind==='connector') return connectorButtonHTML(it, route.items[i+1]?.label||'', i);
      return `<button type="button" class="route-step-card ${it.kind||'stage'}" data-sinfo="${escapeHTML(it.info||'')}"><strong>${escapeHTML(it.label)}</strong><small>Clic para ver</small></button>`;
    }).join('')}</div></div>`).join('')}</div>
    <aside class="route-summary"><h3>${T('important')}</h3><p>${escapeHTML(p.regulated)}</p><p><strong>${T('subjects')}:</strong> ${(p.subjects||[]).map(escapeHTML).join(', ')}</p>${ponderationHTML(p)}${availabilityHTML(p)}${sourceLinks(p.sources)}</aside>
  </div>`;
  document.querySelectorAll('.route-step-card').forEach(btn=>btn.onclick=()=>openRouteLinkModal(btn.querySelector('strong')?.textContent||'Paso', `<p>${escapeHTML(btn.dataset.sinfo||'Consulta la ficha del estudio y las fuentes oficiales asociadas.')}</p>`));
  document.querySelectorAll('.route-connector').forEach(btn=>btn.onclick=()=>openRouteLinkModal(btn.dataset.ctitle, connectionInfoHTML({type:btn.classList.contains('access-link')?'access':btn.classList.contains('critical-link')?'critical':'direct', info:btn.dataset.cinfo}, btn.dataset.next)));
};

