function studySuggestionList(query){
  const q=String(query||'').trim();
  if(q.length<3) return [];
  return programs(q,'all','all').slice(0,12);
}
renderAdventureSuggestions = function(){
  const box=document.getElementById('adventureSuggestions');
  const input=document.getElementById('adventureGoalSearch');
  if(!box||!input) return;
  const q=input.value.trim();
  if(q.length<3){
    box.innerHTML=`<div class="suggestion-help">${escapeHTML(T('minLetters'))}</div>`;
    box.classList.remove('open');
    return;
  }
  const list=studySuggestionList(q);
  box.classList.add('open');
  if(!list.length){
    box.innerHTML=`<div class="suggestion-help">${escapeHTML(T('noSuggestions'))}</div>`;
    return;
  }
  box.innerHTML=list.map(p=>`<button type="button" class="suggestion-item" data-pid="${p.id}"><strong>${escapeHTML(p.name)}</strong><span>${escapeHTML(p.level)} · ${escapeHTML(p.family)}</span></button>`).join('');
  box.querySelectorAll('[data-pid]').forEach(btn=>btn.onclick=()=>{
    const p=state.data.studies.find(x=>x.id===btn.dataset.pid);
    if(!p) return;
    state.adventure.goalText=p.name;
    state.adventure.selectedProgramId=p.id;
    state.adventure.step=3;
    input.value=p.name;
    box.classList.remove('open');
    box.innerHTML='';
    renderAdventure();
    scrollWizard(3);
  });
}

renderAdventure = function(){
  const startOptions=[['eso_cursando','Estoy cursando ESO'],['eso_titulo','Tengo título de ESO'],['eso_sin','No tengo título de ESO'],['bach','Estoy en Bachillerato'],['fpgm','Estoy en Grado Medio'],['fpgs','Estoy en Grado Superior'],['grado','Ya tengo un grado']];
  document.getElementById('adventureStartOptions').innerHTML=startOptions.map(([id,l])=>`<button class="${state.adventure.start===id?'active':''}" data-start="${id}">${escapeHTML(l)}</button>`).join('');
  document.querySelectorAll('[data-start]').forEach(b=>b.onclick=()=>{state.adventure.start=b.dataset.start;state.adventure.step=2;renderAdventure();scrollWizard(2)});
  const priority=['grado-criminologia','grado-medicina','grado-psicologia','grado-arquitectura','grado-derecho','cm-instalaciones-electricas-automaticas','cs-sistemas-electrotecnicos-automatizados','cm-soldadura-caldeiraria','cm-carpinteria-mueble','cs-energias-renovables','grado-ade','grado-educacion-primaria','grado-informatica'];
  const chips=priority.map(id=>state.data.studies.find(p=>p.id===id)).filter(Boolean);
  document.getElementById('adventureGoalOptions').innerHTML=chips.map(p=>`<button data-goal="${escapeHTML(p.name)}">${escapeHTML(p.name.replace('Técnico Superior en ','TS ').replace('Técnico en ','TM ').replace('Grado en ',''))}</button>`).join('');
  document.querySelectorAll('[data-goal]').forEach(b=>b.onclick=()=>{document.getElementById('adventureGoalSearch').value=b.dataset.goal;state.adventure.goalText=b.dataset.goal;const m=programs(state.adventure.goalText);state.adventure.selectedProgramId=m[0]?.id||null;state.adventure.step=3;renderAdventure();scrollWizard(3)});
  const input=document.getElementById('adventureGoalSearch');
  if(input){
    if(input.value!==state.adventure.goalText) input.value=state.adventure.goalText||'';
    input.oninput=e=>{
      state.adventure.goalText=e.target.value;
      state.adventure.selectedProgramId=null;
      renderAdventureSuggestions();
    };
    input.onfocus=renderAdventureSuggestions;
    input.onkeydown=e=>{
      if(e.key==='Enter'){
        e.preventDefault();
        const list=studySuggestionList(input.value);
        if(list[0]){
          state.adventure.goalText=list[0].name;
          state.adventure.selectedProgramId=list[0].id;
          state.adventure.step=3;
          input.value=list[0].name;
          renderAdventure();
          scrollWizard(3);
        }
      }
    };
  }
  renderAdventureSuggestions();
  const matches=programs(state.adventure.goalText);
  const dis=document.getElementById('adventureDisambiguation');
  if(state.adventure.goalText&&isAmbiguous(matches)&&!state.adventure.selectedProgramId){
    dis.innerHTML=`<p class="warning-box small">${T('ambiguity')}</p>`+matches.slice(0,8).map(p=>`<button class="choice-card" data-pid="${p.id}">${escapeHTML(p.name)}<br><small>${escapeHTML(p.family)} · ${escapeHTML(p.level)}</small></button>`).join('');
    dis.querySelectorAll('[data-pid]').forEach(b=>b.onclick=()=>{state.adventure.selectedProgramId=b.dataset.pid;state.adventure.goalText=state.data.studies.find(x=>x.id===b.dataset.pid)?.name||state.adventure.goalText;document.getElementById('adventureGoalSearch').value=state.adventure.goalText;state.adventure.step=3;renderAdventure();scrollWizard(3)});
  } else dis.innerHTML='';
  document.getElementById('adventureQuestions').innerHTML=[
    ['balanced','Ruta equilibrada'],
    ['direct','Ruta más directa'],
    ['open','Mantener alternativas'],
    ['support','Necesito apoyo con materias difíciles'],
    ['near','Priorizar centros cercanos'],
    ['employment','Priorizar empleabilidad']
  ].map(([id,l])=>`<button class="${state.adventure.adjustment===id?'active':''}" data-adjust="${id}">${escapeHTML(l)}</button>`).join('');
  document.querySelectorAll('[data-adjust]').forEach(b=>b.onclick=()=>{state.adventure.adjustment=b.dataset.adjust;renderAdventureResult()});
  document.querySelectorAll('.wizard-step').forEach((el,i)=>el.classList.toggle('active',i+1===state.adventure.step));
  document.querySelectorAll('.wizard-progress span').forEach((el,i)=>el.classList.toggle('active',i+1<=state.adventure.step));
  renderAdventureResult();
};

